using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Generate a personalized greeting message.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name,
        [Description("Optional greeting style: formal or casual")] string style = "casual")
    {
        return style.Equals("formal", StringComparison.OrdinalIgnoreCase)
            ? $"Good day, {name}. It is a pleasure to meet you."
            : $"Hey {name}! 👋 Welcome aboard!";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            Features = new { EnableLogging = true, MaxRequestsPerMinute = 60 }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(UriTemplate = "config://app/endpoints", Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Lists available API endpoints and their descriptions.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Method = "POST", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Method = "GET", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, JsonOptions);
    }
}

